// // This comment suggests that the counter decrements on the rising edge of the clock when the enable input is low.
module async_counter (
    input clk,
    input enable,
    input reset,
    output reg [7:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 8'b00000000;
        else if (enable)
            count <= count + 1;
    end

endmodule
